define float @freeze_sqrt(float %arg) {
  %op = call float @llvm.sqrt.f32(float %arg)
  %freeze = freeze float %op
  ret float %freeze
}

define i8 @neg_nsw_freeze(i8 %a1, i8 %a2) {
  %a = sub nsw i8 %a1, %a2
  %fr = freeze i8 %a
  %neg = sub nsw i8 0, %fr
  ret i8 %neg
}

define i32 @sub_sub1_nsw_nsw(i32 %a, i32 %b, i32 %c) {
  %s1 = sub nsw i32 %a, %b
  %s2 = sub nsw i32 %c, %s1
  ret i32 %s2
}

